// Validate required fields from AI extraction
const data = $json.output;
const errors = [];

if (!data.vendor_name) errors.push('vendor_name is missing');
if (!data.amount || data.amount <= 0) errors.push('amount is missing or invalid');
if (!data.line_items || data.line_items.length === 0) errors.push('no line items found');

// Normalize dates
const normalizeDate = (d) => {
  if (!d) return null;
  const parsed = new Date(d);
  if (isNaN(parsed.getTime())) return null;
  return parsed.toISOString().split('T')[0];
};

return {
  json: {
    valid: errors.length === 0,
    errors: errors,
    data: {
      ...data,
      due_date: normalizeDate(data.due_date),
      txn_date: normalizeDate(data.txn_date),
      currency: data.currency || 'USD'
    }
  }
};

const data = $('Validate Extracted Data').item.json.data;
const vendorId = $('Search vendor').item.json.Id;
const config = $('Config').item.json;

// Build combined description from line items + invoice number
const lineDescriptions = (data.line_items || []).map(item => {
  const qty = item.quantity && item.quantity > 1 ? ` x${item.quantity}` : '';
  return `${item.description}${qty} - ${data.currency} ${item.amount}`;
});

let description = '';
if (data.invoice_number) description += `Invoice #${data.invoice_number}\n`;
description += lineDescriptions.join('\n');

return {
  json: {
    vendorId: vendorId,
    amount: data.amount,
    description: description.substring(0, 4000),
    accountId: config.defaultExpenseAccountId,
    dueDate: data.due_date || '',
    txnDate: data.txn_date || '',
    totalAmt: data.amount
  }
};

// Binary is lost in the main pipeline after AI extraction.
// Reference it by name from Config node which still has attachment_0.
const binaryData = $('Config').item.binary.attachment_0;

return {
  json: {
    "AttachableRef": [{
      "EntityRef": {
        "type": "Bill",
        "value": $('Create Bill').item.json.Id
      }
    }],
    "FileName": binaryData.fileName,
    "ContentType": binaryData.mimeType
  }
};

const jsonString = JSON.stringify($json);
  const buffer = Buffer.from(jsonString, 'utf-8');

return {
    json: $json,
    binary: {          
      myBinaryFile: {
        data: buffer.toString('base64'),
        mimeType: 'application/json',
        fileName: 'data.json'
      }
    }
  };

// Fetch the original PDF binary from Config node by name.
// Binary is lost in the main pipeline after AI extraction,
// but Config still has attachment_0.
const configBinary = $('Config').item.binary;

return {
  json: {},
  binary: configBinary
};

// CRITICAL: Force binary data from database stream to inline base64.
// Without this, QuickBooks upload API fails because n8n v2 stores
// binary as DB streams which lack Content-Length headers.

const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  if (item.binary?.attachment_0) {
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'attachment_0');
    const meta = item.binary.attachment_0;
    item.binary.attachment_0 = {
      data: buffer.toString('base64'),
      mimeType: meta.mimeType,
      fileName: meta.fileName,
      fileExtension: meta.fileExtension || 'pdf',
    };
  }

  if (item.binary?.myBinaryFile) {
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'myBinaryFile');
    const meta = item.binary.myBinaryFile;
    item.binary.myBinaryFile = {
      data: buffer.toString('base64'),
      mimeType: meta.mimeType,
      fileName: meta.fileName,
      fileExtension: meta.fileExtension || 'json',
    };
  }
}

return items;

